mapper.select:
SELECT
    c.*,
    b.kb_name AS kb_name,
    d.file_name AS doc_name
FROM kb_chunk c
LEFT JOIN kb_base b ON c.kb_id = b.kb_id AND b.del_flag = '0'
LEFT JOIN kb_document d ON c.doc_id = d.doc_id AND d.del_flag = '0'
WHERE c.del_flag = '0'

    AND c.chunk_id = #{bo.chunkId}


    AND c.tenant_id = #{bo.tenantId}


    AND c.kb_id = #{bo.kbId}


    AND b.kb_name LIKE CONCAT('%', #{bo.kbName}, '%')


    AND c.doc_id = #{bo.docId}


    AND d.file_name LIKE CONCAT('%', #{bo.docName}, '%')


    AND c.chunk_no = #{bo.chunkNo}


    AND c.chunk_title LIKE CONCAT('%', #{bo.chunkTitle}, '%')


    AND c.content LIKE CONCAT('%', #{bo.content}, '%')


    AND c.content_hash = #{bo.contentHash}


    AND c.token_count = #{bo.tokenCount}


    AND c.char_count = #{bo.charCount}


    AND c.page_no = #{bo.pageNo}


    AND c.section_title LIKE CONCAT('%', #{bo.sectionTitle}, '%')


    AND c.start_offset = #{bo.startOffset}


    AND c.end_offset = #{bo.endOffset}


    AND c.embedding_status = #{bo.embeddingStatus}


    AND c.embedding_id = #{bo.embeddingId}


    AND c.status = #{bo.status}


    AND c.create_by = #{bo.createBy}


    AND c.create_time = #{bo.createTime}


    AND c.update_by = #{bo.updateBy}


    AND c.update_time = #{bo.updateTime}
